func (p *pageState) RawContent() string {
	if p.m.content.pi.itemsStep2 == nil {
		return ""
	}
	start := p.m.content.pi.posMainContent
	if start == -1 {
		start = 0
	}
	source, err := p.m.content.pi.contentSource(p.m.content)
	if err != nil {
		panic(err)
	}
	return string(source[start:])
}
